887	                .elem("Mode", obj.getObjectLockMode());
888	        if (obj.getRetainUntilDate() != null) {
889	            xml.elem("RetainUntilDate", ISO_FORMAT.format(obj.getRetainUntilDate()));
890	        }
891	        xml.end("Retention");
892	        return Response.ok(xml.build()).type(MediaType.APPLICATION_XML).build();
893	    }
894	
895	    // --- Legal Hold ---
896	
897	    private Response handlePutObjectLegalHold(String bucket, String key, String versionId, byte[] body) {
898	        String xml = new String(body, StandardCharsets.UTF_8);
899	        String status = XmlParser.extractFirst(xml, "Status", null);
900	        if (status == null) {
901	            return xmlErrorResponse(new AwsException("MalformedXML",
902	                    "The XML you provided was not well-formed.", 400));
903	        }
904	        s3Service.putObjectLegalHold(bucket, key, versionId, status);
905	        return Response.ok().build();
906	    }
907	
908	    private Response handleGetObjectLegalHold(String bucket, String key, String versionId) {
909	        S3Object obj = s3Service.getObjectLegalHold(bucket, key, versionId);
910	        String status = obj.getLegalHoldStatus() != null ? obj.getLegalHoldStatus() : "OFF";
911	        String xml = new XmlBuilder()
912	                .raw("<?xml version=\"1.0\" encoding=\"UTF-8\"?>")
913	                .start("LegalHold", AwsNamespaces.S3)
914	                .elem("Status", status)
915	                .end("LegalHold")
916	                .build();
917	        return Response.ok(xml).type(MediaType.APPLICATION_XML).build();
918	    }
919	
920	    private void appendObjectHeaders(Response.ResponseBuilder resp, S3Object obj) {
921	        if (obj.getStorageClass() != null) {
922	            resp.header("x-amz-storage-class", obj.getStorageClass());
923	        }
924	        if (obj.getMetadata() != null) {
925	            for (Map.Entry<String, String> entry : obj.getMetadata().entrySet()) {
926	                resp.header("x-amz-meta-" + entry.getKey(), entry.getValue());
927	            }
928	        }
929	        appendChecksumHeaders(resp, obj.getChecksum());
930	        appendLockHeaders(resp, obj);
931	    }
932	
933	    private void appendLockHeaders(Response.ResponseBuilder resp, S3Object obj) {
934	        if (obj.getObjectLockMode() != null) {
935	            resp.header("x-amz-object-lock-mode", obj.getObjectLockMode());
936	        }
937	        if (obj.getRetainUntilDate() != null) {
938	            resp.header("x-amz-object-lock-retain-until-date",
939	                    DateTimeFormatter.ISO_INSTANT.format(obj.getRetainUntilDate()));
940	        }
941	        if (obj.getLegalHoldStatus() != null) {
942	            resp.header("x-amz-object-lock-legal-hold", obj.getLegalHoldStatus());
943	        }
944	    }
945	
946	    // --- Helpers ---
947	
948	    private Response handleCopyObject(String copySource, String destBucket, String destKey,
949	                                      String contentType, HttpHeaders httpHeaders) {
950	        String source = copySource.startsWith("/") ? copySource.substring(1) : copySource;
951	        int slashIndex = source.indexOf('/');
952	        if (slashIndex < 0) {
953	            throw new AwsException("InvalidArgument", "Invalid copy source: " + copySource, 400);
954	        }
955	        String sourceBucket = source.substring(0, slashIndex);
956	        String sourceKey = source.substring(slashIndex + 1);
957	
958	        S3Object copy = s3Service.copyObject(sourceBucket, sourceKey, destBucket, destKey,
959	                httpHeaders.getHeaderString("x-amz-metadata-directive"),
960	                extractUserMetadata(httpHeaders),
961	                httpHeaders.getHeaderString("x-amz-storage-class"),
962	                contentType);
963	        String xml = new XmlBuilder()
964	                .raw("<?xml version=\"1.0\" encoding=\"UTF-8\"?>")
965	                .start("CopyObjectResult", AwsNamespaces.S3)
966	                .elem("LastModified", ISO_FORMAT.format(copy.getLastModified()))
967	                .elem("ETag", copy.getETag())
968	                .end("CopyObjectResult")
969	                .build();
970	        return Response.ok(xml).build();
971	    }
972	
973	    private Response handleGetObjectAttributes(String bucket, String key, String versionId,
974	                                               String objectAttributesHeader, Integer maxParts,
975	                                               Integer partNumberMarker) {
976	        Set<ObjectAttributeName> attributes = ObjectAttributeName.parseHeader(objectAttributesHeader);
977	        GetObjectAttributesResult result = s3Service.getObjectAttributes(bucket, key, versionId,
978	                attributes, maxParts, partNumberMarker);
979	
980	        XmlBuilder xml = new XmlBuilder()
981	                .raw("<?xml version=\"1.0\" encoding=\"UTF-8\"?>")
982	                .start("GetObjectAttributesResponse", AwsNamespaces.S3)
983	                .elem("ETag", result.getETag());
984	        appendChecksum(xml, result.getChecksum());
985	        appendObjectParts(xml, result.getObjectParts());
986	        if (result.getStorageClass() != null) {
987	            xml.elem("StorageClass", result.getStorageClass());
988	        }
989	        if (result.getObjectSize() != null) {
990	            xml.elem("ObjectSize", result.getObjectSize());
991	        }
992	        xml.end("GetObjectAttributesResponse");
993	
994	        Response.ResponseBuilder response = Response.ok(xml.build()).type(MediaType.APPLICATION_XML);
995	        if (result.getLastModified() != null) {
996	            response.header("Last-Modified", RFC_822.format(result.getLastModified()));
997	        }
998	        if (result.getVersionId() != null) {
999	            response.header("x-amz-version-id", result.getVersionId());
1000	        }
1001	        return response.build();
1002	    }
1003	
1004	    private void appendChecksum(XmlBuilder xml, S3Checksum checksum) {
1005	        if (checksum == null || !checksum.hasAnyValue()) {
1006	            return;
1007	        }
1008	        xml.start("Checksum")
1009	                .elem("ChecksumCRC32", checksum.getChecksumCRC32())
1010	                .elem("ChecksumCRC32C", checksum.getChecksumCRC32C())
1011	                .elem("ChecksumCRC64NVME", checksum.getChecksumCRC64NVME())
1012	                .elem("ChecksumSHA1", checksum.getChecksumSHA1())
1013	                .elem("ChecksumSHA256", checksum.getChecksumSHA256())
1014	                .elem("ChecksumType", checksum.getChecksumType())
1015	                .end("Checksum");
1016	    }
1017	
1018	    private void appendObjectParts(XmlBuilder xml, GetObjectAttributesParts objectParts) {
1019	        if (objectParts == null) {
1020	            return;
1021	        }
1022	        xml.start("ObjectParts")
1023	                .elem("IsTruncated", objectParts.isTruncated())
1024	                .elem("MaxParts", objectParts.getMaxParts())
1025	                .elem("NextPartNumberMarker", objectParts.getNextPartNumberMarker())
1026	                .elem("PartNumberMarker", objectParts.getPartNumberMarker());
1027	        for (Part part : objectParts.getParts()) {
1028	            xml.start("Part")
1029	                    .elem("ChecksumCRC32", part.getChecksum().getChecksumCRC32())
1030	                    .elem("ChecksumCRC32C", part.getChecksum().getChecksumCRC32C())
1031	                    .elem("ChecksumCRC64NVME", part.getChecksum().getChecksumCRC64NVME())
1032	                    .elem("ChecksumSHA1", part.getChecksum().getChecksumSHA1())
1033	                    .elem("ChecksumSHA256", part.getChecksum().getChecksumSHA256())
1034	                    .elem("PartNumber", part.getPartNumber())
1035	                    .elem("Size", part.getSize())
1036	                    .end("Part");
1037	        }
1038	        xml.elem("PartsCount", objectParts.getPartsCount())
1039	                .end("ObjectParts");
1040	    }
1041	
1042	    private void appendChecksumHeaders(Response.ResponseBuilder resp, S3Checksum checksum) {
1043	        if (checksum == null) {
1044	            return;
1045	        }
1046	        if (checksum.getChecksumSHA1() != null) {
1047	            resp.header("x-amz-checksum-sha1", checksum.getChecksumSHA1());
1048	        }
1049	        if (checksum.getChecksumSHA256() != null) {
1050	            resp.header("x-amz-checksum-sha256", checksum.getChecksumSHA256());
1051	        }
1052	    }
1053	
1054	    private Map<String, String> extractUserMetadata(HttpHeaders httpHeaders) {
1055	        Map<String, String> metadata = new LinkedHashMap<>();
1056	        for (Map.Entry<String, List<String>> entry : httpHeaders.getRequestHeaders().entrySet()) {
1057	            String headerName = entry.getKey().toLowerCase(Locale.ROOT);
1058	            if (!headerName.startsWith("x-amz-meta-")) {
1059	                continue;
1060	            }
1061	            String key = headerName.substring("x-amz-meta-".length());
1062	            if (!key.isBlank() && !entry.getValue().isEmpty()) {
1063	                metadata.put(key, entry.getValue().get(0));
1064	            }
1065	        }
1066	        return metadata;
1067	    }
1068	
1069	    private void validateChecksumHeaders(HttpHeaders httpHeaders, byte[] data) {
1070	        String sha1 = httpHeaders.getHeaderString("x-amz-checksum-sha1");
1071	        if (sha1 != null && !sha1.equals(S3Checksum.sha1Base64(data))) {
1072	            throw new AwsException("BadDigest", "The SHA1 checksum you specified did not match the payload.", 400);
1073	        }
1074	
1075	        String sha256 = httpHeaders.getHeaderString("x-amz-checksum-sha256");
1076	        if (sha256 != null && !sha256.equals(S3Checksum.sha256Base64(data))) {
1077	            throw new AwsException("BadDigest", "The SHA256 checksum you specified did not match the payload.", 400);
1078	        }
1079	    }
1080	
1081	    private Response xmlErrorResponse(AwsException e) {
1082	        String xml = new XmlBuilder()
1083	                .raw("<?xml version=\"1.0\" encoding=\"UTF-8\"?>")
1084	                .start("Error")
1085	                .elem("Code", e.getErrorCode())
1086	                .elem("Message", e.getMessage())
1087	                .elem("RequestId", java.util.UUID.randomUUID().toString())
1088	                .end("Error")
1089	                .build();
1090	        return Response.status(e.getHttpStatus()).entity(xml).type(MediaType.APPLICATION_XML).build();
1091	    }
1092	
1093	    private boolean hasQueryParam(UriInfo uriInfo, String param) {
1094	        if (uriInfo.getQueryParameters().containsKey(param)) return true;
1095	        String query = uriInfo.getRequestUri().getQuery();
1096	        if (query == null) return false;
1097	        return query.equals(param) || query.contains(param + "&") || query.contains("&" + param);
1098	    }
