package io.github.hectorvent.floci.services.s3;

import jakarta.ws.rs.container.ContainerRequestContext;
import jakarta.ws.rs.container.ContainerRequestFilter;
import jakarta.ws.rs.container.PreMatching;
import jakarta.ws.rs.core.UriBuilder;
import jakarta.ws.rs.ext.Provider;
import java.net.URI;
import java.util.Locale;

@Provider
@PreMatching
public class S3VirtualHostFilter implements ContainerRequestFilter {

    @Override
    public void filter(ContainerRequestContext requestContext) {
        String host = requestContext.getHeaderString("Host");
        if (host == null || host.isBlank()) {
            return;
        }

        String bucket = extractVirtualHostBucket(host);
        if (bucket == null) {
            return;
        }

        URI uri = requestContext.getUriInfo().getRequestUri();
        String path = uri.getRawPath();
        String normalizedPath = (path == null || path.isEmpty()) ? "/" : path;

        String newPath = "/" + bucket;
        if (!"/".equals(normalizedPath)) {
            newPath += normalizedPath.startsWith("/") ? normalizedPath : "/" + normalizedPath;
        }

        URI newUri = UriBuilder.fromUri(uri)
                .replacePath(newPath)
                .build();

        requestContext.setRequestUri(newUri);
    }

    private String extractVirtualHostBucket(String hostHeader) {
        String host = hostHeader;
        int commaIndex = host.indexOf(',');
        if (commaIndex >= 0) {
            host = host.substring(0, commaIndex);
        }
        host = host.trim();
        if (host.isEmpty()) {
            return null;
        }

        if (host.startsWith("[")) {
            return null;
        }

        int colonIndex = host.indexOf(':');
        if (colonIndex >= 0) {
            host = host.substring(0, colonIndex);
        }
        if (host.endsWith(".")) {
            host = host.substring(0, host.length() - 1);
        }

        String lowerHost = host.toLowerCase(Locale.ROOT);
        if (lowerHost.equals("localhost") || lowerHost.equals("s3") || lowerHost.startsWith("s3.")) {
            return null;
        }

        String suffix = ".localhost";
        if (lowerHost.endsWith(suffix) && lowerHost.length() > suffix.length()) {
            return host.substring(0, host.length() - suffix.length());
        }

        int s3Index = lowerHost.indexOf(".s3.");
        if (s3Index > 0) {
            return host.substring(0, s3Index);
        }

        suffix = ".s3.amazonaws.com";
        if (lowerHost.endsWith(suffix) && lowerHost.length() > suffix.length()) {
            return host.substring(0, host.length() - suffix.length());
        }

        return null;
    }
}

